package gkrapi_test

import (
	"os"
	"testing"

	"github.com/consensys/gnark-crypto/ecc"
	"github.com/consensys/gnark/backend/plonk"
	"github.com/consensys/gnark/backend/witness"
	"github.com/stretchr/testify/require"
)

// TestGkrCircuitDeserialization verifies that GKR blueprint types are properly
// registered for CBOR deserialization when only importing the constraint system
// package (via plonk.NewCS), without importing gkrapi.
//
// This test reads a pre-generated constraint system file that contains GKR blueprints.
// The file is generated by internal/gkr/test_vectors/generate.go during code generation.
func TestGkrCircuitDeserialization(t *testing.T) {
	// Open the pre-generated constraint system file
	f, err := os.Open("../../internal/gkr/test_vectors/testdata/gkr_circuit_bn254.scs")
	require.NoError(t, err)
	defer f.Close()

	// Create a new constraint system - this imports constraint/bn254 which
	// should trigger GKR blueprint registration via init()
	ccs := plonk.NewCS(ecc.BN254)

	// Deserialize - this will panic if GKR blueprint types aren't registered
	n, err := ccs.ReadFrom(f)
	require.NoError(t, err)
	require.NotZero(t, n)
}

// TestGkrPoseidon2RoundTrip is an end-to-end integration test for a GKR-backed
// circuit that has been serialized and deserialized across process boundaries.
// It complements TestGkrCircuitDeserialization, which only checks that
// deserialization succeeds: this test additionally drives the prover via
// ccs.Solve, which invokes the BlueprintProve.Solve path and ultimately the
// curve-specific GKR Prove. Without this step, type-shape problems in the
// deserialized GkrProvingSchedule (e.g. CBOR producing *GkrSkipLevel pointers
// instead of GkrSkipLevel values) are invisible.
//
// Inputs are pre-generated by internal/gkr/test_vectors/generate.go and the
// circuit uses Poseidon2 so the schedule contains all three level variants
// (GkrSkipLevel, GkrSumcheckLevel, GkrSingleSourceZeroCheckLevel).
func TestGkrPoseidon2RoundTrip(t *testing.T) {
	ccs := plonk.NewCS(ecc.BLS12_377)

	scsFile, err := os.Open("../../internal/gkr/test_vectors/testdata/gkr_poseidon2_bls12377.scs")
	require.NoError(t, err)
	defer scsFile.Close()
	_, err = ccs.ReadFrom(scsFile)
	require.NoError(t, err)

	w, err := witness.New(ecc.BLS12_377.ScalarField())
	require.NoError(t, err)
	wtnsFile, err := os.Open("../../internal/gkr/test_vectors/testdata/gkr_poseidon2_bls12377.wtns")
	require.NoError(t, err)
	defer wtnsFile.Close()
	_, err = w.ReadFrom(wtnsFile)
	require.NoError(t, err)

	_, err = ccs.Solve(w)
	require.NoError(t, err)
}
